from pathlib import Path

ROOT = Path.cwd()


def replace_once(path, old, new, description):
    file_path = ROOT / path
    text = file_path.read_text(encoding="utf-8")

    if new in text:
        print(f"SKIP already applied: {description}")
        return False

    if old not in text:
        raise RuntimeError(f"Could not find expected block for: {description} in {path}")

    file_path.write_text(text.replace(old, new, 1), encoding="utf-8")
    print(f"APPLIED: {description}")
    return True


def insert_after(path, marker, insert_text, description):
    file_path = ROOT / path
    text = file_path.read_text(encoding="utf-8")

    if insert_text.strip() in text:
        print(f"SKIP already applied: {description}")
        return False

    if marker not in text:
        raise RuntimeError(f"Could not find marker for: {description} in {path}")

    file_path.write_text(text.replace(marker, marker + insert_text, 1), encoding="utf-8")
    print(f"APPLIED: {description}")
    return True


